function renderOwnerEmailHTML(lead: LeadPayload): string {
  return `<pre style="font-family:monospace;font-size:14px;">
Lead mới từ ${PAGE_URL}

────────────────────────────────
Tên:       ${lead.name}
SĐT:       ${formatPhoneVN(lead.phone)}
Email:     ${lead.email}
Source:    ${lead.utm_source || "direct"}
Campaign:  ${lead.utm_campaign || "-"}
Thời gian: ${timestampVN()}
${lead.message ? `Ghi chú:   ${lead.message}` : ""}
────────────────────────────────

Quick actions:
- Gọi:   tel:${lead.phone.replace(/\D/g, "")}
- Zalo:  https://zalo.me/${lead.phone.replace(/\D/g, "")}
- Email: mailto:${lead.email}
</pre>`;
}

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const result = validate(body);
    if (!result.ok) {
      return NextResponse.json({ ok: false, error: result.error }, { status: 400 });
    }
    const lead = result.data;

    const [leadEmail, ownerEmail] = await Promise.all([
      resend.emails.send({
        from: FROM,
        to: lead.email,
        subject: `${lead.name}, đã ghi nhận đăng ký ${OFFER.product_name}`,
        html: renderLeadEmailHTML(lead),
        replyTo: OWNER,
      }),
      resend.emails.send({
        from: FROM,
        to: OWNER,
        subject: `🔥 Lead mới — ${lead.name} (${formatPhoneVN(lead.phone)}) — ${OFFER.product_name}`,
        html: renderOwnerEmailHTML(lead),
        replyTo: lead.email,
      }),
    ]);

    if (leadEmail.error || ownerEmail.error) {
      console.error("Resend error:", leadEmail.error, ownerEmail.error);
      return NextResponse.json(
        { ok: false, error: "Email service tạm lỗi, anh/chị thử lại sau" },
        { status: 500 },
      );
    }

    return NextResponse.json({ ok: true });
  } catch (err) {
    console.error("/api/submit fatal:", err);
    return NextResponse.json({ ok: false, error: "Lỗi server" }, { status: 500 });
  }
}
